16	
17	`include "defines.svh"
18	
19	import defines::*;
20	
21	//
22	// Instruction Pipeline - Instruction Decode Stage
23	// Populate the decoded_instruction_t structure with fields from
24	// the instruction. The structure contains control fields will be
25	// used later in the pipeline.
26	//
27	// This also handles interrupts. When an interrupt is pending, an existing
28	// instruction is replaced with one that has the trap flag set. This works
29	// similar to the way traps from earlier stages in the pipeline are handled
30	// and is necessary to make sure interrupts are precise (from the software
31	// perspective, the interrupt appears  to occur on a boundary between two
32	// instructions, with every prior instruction executing, and every subsequent
33	// instruction not). We must do it this way because:
34	// - Instructions can retire out of order
35	// - There may be pending instructions in the pipeline for the thread that
36	//   will cause a rollback in a subsequent cycle.
37	//
38	// Register port to operand mapping
39	//                                               store
40	//       format           op1     op2    mask    value
41	// +-------------------+-------+-------+-------+-------+
42	// | R - scalar/scalar |   s1  |   s2  |       |       |
43	// | R - vector/scalar |   v1  |   s2  |  s1   |       |
44	// | R - vector/vector |   v1  |   v2  |  s2   |       |
45	// | I - scalar        |   s1  |  imm  |  n/a  |       |
46	// | I - vector        |   v1  |  imm  |  s2   |       |
47	// | M - scalar        |   s1  |  imm  |  n/a  |  s2   |
48	// | M - block         |   s1  |  imm  |  s2   |  v2   |
49	// | M - scatter/gather|   v1  |  imm  |  s2   |  v2   |
50	// | C                 |   s1  |  imm  |       |       |
51	// | B                 |   s1  |       |       |       |
52	// +-------------------+-------+-------+-------+-------+
53	//
54	
55	module instruction_decode_stage(
56	    input                         clk,
57	    input                         reset,
58	
59	    // From ifetch_data_stage
60	    input                         ifd_instruction_valid,
61	    input scalar_t                ifd_instruction,
62	    input                         ifd_inst_injected,
63	    input scalar_t                ifd_pc,
64	    input local_thread_idx_t      ifd_thread_idx,
65	    input                         ifd_alignment_fault,
66	    input                         ifd_supervisor_fault,
67	    input                         ifd_page_fault,
68	    input                         ifd_executable_fault,
69	    input                         ifd_tlb_miss,
70	
71	    // From dcache_data_stage
72	    input local_thread_bitmap_t   dd_load_sync_pending,
73	
74	    // From l1_l2_interface
75	    input local_thread_bitmap_t   sq_store_sync_pending,
76	
77	    // To thread_select_stage
78	    output decoded_instruction_t  id_instruction,
79	    output logic                  id_instruction_valid,
80	    output local_thread_idx_t     id_thread_idx,
81	
82	    // From io_request_queue
83	    input local_thread_bitmap_t   ior_pending,
84	
85	    // From control_registers
86	    input local_thread_bitmap_t   cr_interrupt_en,
87	    input local_thread_bitmap_t   cr_interrupt_pending,
88	
89	    // From on_chip_debugger
90	    input                         ocd_halt,
91	
92	    // From writeback_stage
93	    input                         wb_rollback_en,
94	    input local_thread_idx_t      wb_rollback_thread_idx);
95	
96	    localparam T = 1'b1;
97	    localparam F = 1'b0;
98	
99	    typedef enum logic[2:0] {
100	        IMM_ZERO,
101	        IMM_23_15,  // Masked immediate arithmetic
102	        IMM_23_10,  // Unmasked immediate arithmetic
103	        IMM_24_15,  // Masked memory access
104	        IMM_24_10,  // Unmasked memory access
105	        IMM_24_5,   // Small branch offset (multiply by four)
106	        IMM_24_0,   // Large branch offset (multiply by four)
107	        IMM_EXT_19  // 19 bit extended immediate value
108	    } imm_loc_t;
109	
110	    typedef enum logic[1:0] {
111	        SCLR1_NONE,
112	        SCLR1_14_10,
113	        SCLR1_4_0
114	    } scalar1_loc_t;
115	
116	    typedef enum logic[2:0] {
117	        SCLR2_NONE,
118	        SCLR2_19_15,
119	        SCLR2_14_10,
120	        SCLR2_9_5
121	    } scalar2_loc_t;
122	
123	    struct packed {
124	        logic illegal;
125	        logic dest_vector;
126	        logic has_dest;
127	        imm_loc_t imm_loc;
128	        scalar1_loc_t scalar1_loc;
129	        scalar2_loc_t scalar2_loc;
130	        logic has_vector1;
131	        logic has_vector2;
132	        logic vector_sel2_9_5;    // Else is src2. Only for stores.
133	        logic op1_vector;
134	        op2_src_t op2_src;
135	        mask_src_t mask_src;
136	        logic store_value_vector;
137	        logic call;
138	    } dlut_out;
139	
140	    decoded_instruction_t decoded_instr_nxt;
141	    logic nop;
142	    logic fmt_r;
143	    logic fmt_i;
144	    logic fmt_m;
145	    logic getlane;
146	    logic compare;
147	    alu_op_t alu_op;
148	    memory_op_t memory_access_type;
149	    register_idx_t scalar_sel2;
150	    logic has_trap;
151	    logic syscall;
152	    logic breakpoint;
153	    logic raise_interrupt;
154	    local_thread_bitmap_t masked_interrupt_flags;
155	    logic unary_arith;
156	
157	    // I originally tried to structure the instruction set so that this could
158	    // determine the format of the instruction from the first 7 bits. Those
159	    // index into this ROM table that returns the decoded information. This
160	    // has become less true as the instruction set has evolved. Also, synthesis
161	    // tools just turn this into random logic. Should revisit this at some point.
162	    always_comb
163	    begin
164	        unique casez (ifd_instruction[31:25])
165	            // Format R (register arithmetic)
166	            7'b110_000_?: dlut_out = {F, F, T, IMM_ZERO, SCLR1_4_0, SCLR2_19_15,   F, F, F, F, OP2_SRC_SCALAR2, MASK_SRC_ALL_ONES, F, F};
167	            7'b110_001_?: dlut_out = {F, T, T, IMM_ZERO, SCLR1_4_0, SCLR2_19_15,   T, F, F, T, OP2_SRC_SCALAR2, MASK_SRC_ALL_ONES, F, F};
168	            7'b110_010_?: dlut_out = {F, T, T, IMM_ZERO, SCLR1_14_10, SCLR2_19_15, T, F, F, T, OP2_SRC_SCALAR2, MASK_SRC_SCALAR1, F, F};
169	            7'b110_100_?: dlut_out = {F, T, T, IMM_ZERO, SCLR1_14_10, SCLR2_NONE,  T, T, F, T, OP2_SRC_VECTOR2, MASK_SRC_ALL_ONES, F, F};
170	            7'b110_101_?: dlut_out = {F, T, T, IMM_ZERO, SCLR1_4_0, SCLR2_14_10,   T, T, F, T, OP2_SRC_VECTOR2, MASK_SRC_SCALAR2, F, F};
171	
172	            // Format I (immediate arithmetic)
173	            7'b0_00_????: dlut_out = {F, F, T, IMM_23_10, SCLR1_4_0, SCLR2_NONE,   F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
174	            7'b0_01_????: dlut_out = {F, T, T, IMM_23_10, SCLR1_4_0, SCLR2_NONE,   T, F, F, T, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
175	            7'b0_10_????: dlut_out = {F, F, T, IMM_EXT_19, SCLR1_4_0, SCLR2_NONE,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
176	            7'b0_11_????: dlut_out = {F, T, T, IMM_23_15, SCLR1_4_0, SCLR2_14_10,  T, F, F, T, OP2_SRC_IMMEDIATE, MASK_SRC_SCALAR2, F, F};
177	
178	            // Format M (memory)
179	            // Store
180	            7'b10_0_0000: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_9_5,     F, F, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
181	            7'b10_0_0001: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_9_5,     F, F, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
182	            7'b10_0_0010: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_9_5,     T, F, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
183	            7'b10_0_0011: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_9_5,     F, F, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
184	            7'b10_0_0100: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_9_5,     F, F, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
185	            7'b10_0_0101: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_9_5,     F, F, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
186	            7'b10_0_0110: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_9_5,     F, F, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
187	            7'b10_0_0111: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    F, T, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, T, F};
188	            7'b10_0_1000: dlut_out = {F, F, F, IMM_24_15, SCLR1_4_0, SCLR2_14_10, F, T, T, F, OP2_SRC_IMMEDIATE, MASK_SRC_SCALAR2, T, F};
189	            7'b10_0_1101: dlut_out = {F, F, F, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, T, T, T, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, T, F};
190	            7'b10_0_1110: dlut_out = {F, F, F, IMM_24_15, SCLR1_4_0, SCLR2_14_10, T, T, T, T, OP2_SRC_IMMEDIATE, MASK_SRC_SCALAR2, T, F};
191	
192	            // Load
193	            7'b10_1_0000: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
194	            7'b10_1_0001: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
195	            7'b10_1_0010: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
196	            7'b10_1_0011: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
197	            7'b10_1_0100: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
198	            7'b10_1_0101: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
199	            7'b10_1_0110: dlut_out = {F, F, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
200	            7'b10_1_0111: dlut_out = {F, T, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
201	            7'b10_1_1000: dlut_out = {F, T, T, IMM_24_15, SCLR1_4_0, SCLR2_14_10, T, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_SCALAR2, F, F};
202	            7'b10_1_1101: dlut_out = {F, T, T, IMM_24_10, SCLR1_4_0, SCLR2_NONE,    T, T, F, T, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
203	            7'b10_1_1110: dlut_out = {F, T, T, IMM_24_15, SCLR1_4_0, SCLR2_14_10, T, T, F, T, OP2_SRC_IMMEDIATE, MASK_SRC_SCALAR2, F, F};
204	
205	            // Format C (cache control)
206	            7'b1110_000: dlut_out = {F, F, F,  IMM_24_15, SCLR1_4_0, SCLR2_9_5,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
207	            7'b1110_001: dlut_out = {F, F, F,  IMM_24_15, SCLR1_4_0, SCLR2_NONE,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
208	            7'b1110_010: dlut_out = {F, F, F,  IMM_24_15, SCLR1_4_0, SCLR2_NONE,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
209	            7'b1110_011: dlut_out = {F, F, F,  IMM_24_15, SCLR1_4_0, SCLR2_NONE,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
210	            7'b1110_100: dlut_out = {F, F, F,  IMM_24_15, SCLR1_NONE, SCLR2_NONE, F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
211	            7'b1110_101: dlut_out = {F, F, F,  IMM_24_15, SCLR1_4_0, SCLR2_NONE,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
212	            7'b1110_110: dlut_out = {F, F, F,  IMM_24_15, SCLR1_NONE, SCLR2_NONE, F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
213	            7'b1110_111: dlut_out = {F, F, F,  IMM_24_15, SCLR1_4_0, SCLR2_9_5,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
214	
215	            // Format B (branch)
216	            7'b1111_000: dlut_out = {F, F, F, IMM_24_5, SCLR1_4_0, SCLR2_NONE,   F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
217	            7'b1111_001: dlut_out = {F, F, F, IMM_24_5, SCLR1_4_0, SCLR2_NONE,   F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
218	            7'b1111_010: dlut_out = {F, F, F, IMM_24_5, SCLR1_4_0, SCLR2_NONE,   F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
219	            7'b1111_011: dlut_out = {F, F, F, IMM_24_0, SCLR1_NONE, SCLR2_NONE,  F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
220	            7'b1111_100: dlut_out = {F, F, T, IMM_24_0, SCLR1_NONE, SCLR2_NONE,  F, F, F, F, OP2_SRC_SCALAR2, MASK_SRC_ALL_ONES, F, T};
221	            7'b1111_110: dlut_out = {F, F, T, IMM_24_5, SCLR1_4_0, SCLR2_NONE,   F, F, F, F, OP2_SRC_SCALAR2, MASK_SRC_ALL_ONES, F, T};
222	            7'b1111_111: dlut_out = {F, F, T, IMM_24_5, SCLR1_4_0, SCLR2_NONE,   F, F, F, F, OP2_SRC_SCALAR2, MASK_SRC_ALL_ONES, F, F};
223	
224	            // Invalid instruction format
225	            default: dlut_out = {T, F, F, IMM_ZERO, SCLR1_NONE, SCLR2_NONE, F, F, F, F, OP2_SRC_IMMEDIATE, MASK_SRC_ALL_ONES, F, F};
226	        endcase
227	    end
228	
229	    assign fmt_r = ifd_instruction[31:29] == 3'b110;    // register arithmetic
230	    assign fmt_i = ifd_instruction[31] == 1'b0;    // immediate arithmetic
231	    assign fmt_m = ifd_instruction[31:30] == 2'b10;
232	    assign getlane = (fmt_r || fmt_i) && alu_op == OP_GETLANE;
233	
234	    assign syscall = fmt_i && 6'(ifd_instruction[28:24]) == OP_SYSCALL;
235	    assign breakpoint = fmt_r && ifd_instruction[25:20] == OP_BREAKPOINT;
236	    assign nop = ifd_instruction == INSTRUCTION_NOP;
237	    assign has_trap = (ifd_instruction_valid
238	        && (dlut_out.illegal || syscall || breakpoint || raise_interrupt))
239	        || ifd_alignment_fault || ifd_tlb_miss
240	        || ifd_supervisor_fault
241	        || ifd_page_fault || ifd_executable_fault;
242	
243	    // Check for TLB miss first, since permission bits are not valid if there
244	    // is a TLB miss. The order of the remaining faults should match that in
245	    // dcache_data_stage for consistency.
246	    always_comb
247	    begin
248	        if (raise_interrupt)
249	            decoded_instr_nxt.trap_cause = {2'b00, TT_INTERRUPT};
250	        else if (ifd_tlb_miss)
251	            decoded_instr_nxt.trap_cause = {2'b00, TT_TLB_MISS};
252	        else if (ifd_page_fault)
253	            decoded_instr_nxt.trap_cause = {2'b00, TT_PAGE_FAULT};
254	        else if (ifd_supervisor_fault)
255	            decoded_instr_nxt.trap_cause = {2'b00, TT_SUPERVISOR_ACCESS};
256	        else if (ifd_alignment_fault)
257	            decoded_instr_nxt.trap_cause = {2'b00, TT_UNALIGNED_ACCESS};
258	        else if (ifd_executable_fault)
259	            decoded_instr_nxt.trap_cause = {2'b00, TT_NOT_EXECUTABLE};
260	        else if (dlut_out.illegal)
261	            decoded_instr_nxt.trap_cause = {2'b00, TT_ILLEGAL_INSTRUCTION};
262	        else if (syscall)
263	            decoded_instr_nxt.trap_cause = {2'b00, TT_SYSCALL};
264	        else if (breakpoint)
265	            decoded_instr_nxt.trap_cause = {2'b00, TT_BREAKPOINT};
266	        else
267	            decoded_instr_nxt.trap_cause = {2'b00, TT_RESET};
268	    end
269	
270	    assign decoded_instr_nxt.injected = ifd_inst_injected;
271	
272	    // Subtle: Certain instructions need to be issued twice, including I/O
273	    // requests and synchronized memory accesses. The first queues the
274	    // transaction and the second collects the result. Because the first
275	    // instruction updates internal state, bad things would happen if an
276	    // interrupt were dispatched between them. To avoid this, don't dispatch
277	    // an interrupt if the first instruction has been issued (indicated by
278	    // dd_load_sync_pending, ior_pending, or sq_store_sync_pending).
279	    assign masked_interrupt_flags = cr_interrupt_pending & cr_interrupt_en
280	        & ~ior_pending & ~dd_load_sync_pending & ~sq_store_sync_pending;
281	    assign raise_interrupt = masked_interrupt_flags[ifd_thread_idx] && !ocd_halt;
282	    assign decoded_instr_nxt.has_trap = has_trap;
283	
284	    assign unary_arith = fmt_r && (alu_op == OP_CLZ
285	        || alu_op == OP_CTZ
286	        || alu_op == OP_MOVE
287	        || alu_op == OP_FTOI
288	        || alu_op == OP_RECIPROCAL
289	        || alu_op == OP_SEXT8
290	        || alu_op == OP_SEXT16
291	        || alu_op == OP_ITOF)
292	        && dlut_out.mask_src != MASK_SRC_SCALAR1;
293	    assign decoded_instr_nxt.has_scalar1 = dlut_out.scalar1_loc != SCLR1_NONE && !nop
294	        && !has_trap && !unary_arith;
295	    always_comb
296	    begin
297	        unique case (dlut_out.scalar1_loc)
298	            SCLR1_14_10: decoded_instr_nxt.scalar_sel1 = ifd_instruction[14:10];
299	            default: decoded_instr_nxt.scalar_sel1 = ifd_instruction[4:0]; //  src1
300	        endcase
301	    end
302	
303	    assign decoded_instr_nxt.has_scalar2 = dlut_out.scalar2_loc != SCLR2_NONE && !nop
304	        && !has_trap;
305	
306	    // XXX: assigning this directly to decoded_instr_nxt.scalar_sel2 causes Verilator issues when
307	    // other blocks read it. Added another signal to work around this.
308	    always_comb
309	    begin
310	        unique case (dlut_out.scalar2_loc)
311	            SCLR2_14_10: scalar_sel2 = ifd_instruction[14:10];
312	            SCLR2_19_15: scalar_sel2 = ifd_instruction[19:15];
313	            SCLR2_9_5: scalar_sel2 = ifd_instruction[9:5];
314	            default: scalar_sel2 = 0;
315	        endcase
316	    end
317	
318	    assign decoded_instr_nxt.scalar_sel2 = scalar_sel2;
319	    assign decoded_instr_nxt.has_vector1 = dlut_out.has_vector1 && !nop && !has_trap;
320	    assign decoded_instr_nxt.vector_sel1 = ifd_instruction[4:0];
321	    assign decoded_instr_nxt.has_vector2 = dlut_out.has_vector2 && !nop && !has_trap;
322	    always_comb
323	    begin
324	        if (dlut_out.vector_sel2_9_5)
325	            decoded_instr_nxt.vector_sel2 = ifd_instruction[9:5];
326	        else
327	            decoded_instr_nxt.vector_sel2 = ifd_instruction[19:15];
328	    end
329	
330	    assign decoded_instr_nxt.has_dest = dlut_out.has_dest && !nop && !has_trap;
331	
332	    assign decoded_instr_nxt.dest_vector = dlut_out.dest_vector && !compare
333	        && !getlane;
334	    assign decoded_instr_nxt.dest_reg = dlut_out.call ? REG_RA : ifd_instruction[9:5];
335	    assign decoded_instr_nxt.call = dlut_out.call;
336	    always_comb
337	    begin
338	        if (fmt_i)
339	            alu_op = alu_op_t'({1'b0, ifd_instruction[28:24]});
340	        else if (dlut_out.call)
341	            alu_op = OP_MOVE;    // Treat a call as move ra, pc
342	        else
343	            alu_op = alu_op_t'(ifd_instruction[25:20]); // Format R
344	    end
345	
346	    assign decoded_instr_nxt.alu_op = alu_op;
347	    assign decoded_instr_nxt.mask_src = dlut_out.mask_src;
348	    assign decoded_instr_nxt.store_value_vector = dlut_out.store_value_vector;
349	
350	    // Decode operand source ports, checking specifically for PC operands
351	    always_comb
352	    begin
353	        if (dlut_out.op1_vector)
354	            decoded_instr_nxt.op1_src = OP1_SRC_VECTOR1;
355	        else
356	            decoded_instr_nxt.op1_src = OP1_SRC_SCALAR1;
357	    end
358	
359	    assign decoded_instr_nxt.op2_src = dlut_out.op2_src;
360	
361	    always_comb
362	    begin
363	        unique case (dlut_out.imm_loc)
364	            IMM_EXT_19: decoded_instr_nxt.immediate_value = { ifd_instruction[23:10], ifd_instruction[4:0], 13'd0 };
365	            IMM_23_15: decoded_instr_nxt.immediate_value = scalar_t'($signed(ifd_instruction[23:15]));
366	            IMM_23_10: decoded_instr_nxt.immediate_value = scalar_t'($signed(ifd_instruction[23:10]));
367	            IMM_24_15: decoded_instr_nxt.immediate_value = scalar_t'($signed(ifd_instruction[24:15]));
368	            IMM_24_10: decoded_instr_nxt.immediate_value = scalar_t'($signed(ifd_instruction[24:10]));
369	
370	            // Branch offsets are multiplied by four
371	            IMM_24_5: decoded_instr_nxt.immediate_value = scalar_t'($signed({ifd_instruction[24:5], 2'b00}));
372	            IMM_24_0: decoded_instr_nxt.immediate_value = scalar_t'($signed({ifd_instruction[24:0], 2'b00}));
373	            default: decoded_instr_nxt.immediate_value = 0;
374	        endcase
375	    end
376	
377	    assign decoded_instr_nxt.branch_type = branch_type_t'(ifd_instruction[27:25]);
378	    assign decoded_instr_nxt.branch = ifd_instruction[31:28] == 4'b1111
379	        && !has_trap;
380	    assign decoded_instr_nxt.pc = ifd_pc;
381	
382	    always_comb
383	    begin
384	        if (has_trap)
385	            decoded_instr_nxt.pipeline_sel = PIPE_INT_ARITH;
386	        else if (fmt_r || fmt_i)
387	        begin
388	            if (alu_op[5] || alu_op == OP_MULL_I || alu_op == OP_MULH_U
389	                 || alu_op == OP_MULH_I || alu_op == OP_FTOI)
390	                decoded_instr_nxt.pipeline_sel = PIPE_FLOAT_ARITH;
391	            else
392	                decoded_instr_nxt.pipeline_sel = PIPE_INT_ARITH;
393	        end
394	        else if (ifd_instruction[31:28] == 4'b1111)
395	            decoded_instr_nxt.pipeline_sel = PIPE_INT_ARITH; // branches evaluated in integer pipeline
396	        else
397	            decoded_instr_nxt.pipeline_sel = PIPE_MEM;
398	    end
399	
400	    assign memory_access_type = memory_op_t'(ifd_instruction[28:25]);
401	    assign decoded_instr_nxt.memory_access_type = memory_access_type;
402	    assign decoded_instr_nxt.memory_access = ifd_instruction[31:30] == 2'b10
403	        && !has_trap;
404	    assign decoded_instr_nxt.load = ifd_instruction[29]
405	        && fmt_m;
406	    assign decoded_instr_nxt.cache_control = ifd_instruction[31:28] == 4'b1110
407	         && !has_trap;
408	    assign decoded_instr_nxt.cache_control_op = cache_op_t'(ifd_instruction[27:25]);
409	
410	    always_comb
411	    begin
412	        if (ifd_instruction[31:30] == 2'b10
413	            && (memory_access_type == MEM_SCGATH
414	            || memory_access_type == MEM_SCGATH_M))
415	        begin
416	            // Scatter/Gather access
417	            decoded_instr_nxt.last_subcycle = subcycle_t'(NUM_VECTOR_LANES - 1);
418	        end
419	        else
420	            decoded_instr_nxt.last_subcycle = 0;
421	    end
422	
423	    assign decoded_instr_nxt.creg_index = control_register_t'(ifd_instruction[4:0]);
424	
425	    assign compare = (fmt_r || fmt_i)
426	        && (alu_op == OP_CMPEQ_I
427	        || alu_op == OP_CMPNE_I
428	        || alu_op == OP_CMPGT_I
429	        || alu_op == OP_CMPGE_I
430	        || alu_op == OP_CMPLT_I
431	        || alu_op == OP_CMPLE_I
432	        || alu_op == OP_CMPGT_U
433	        || alu_op == OP_CMPGE_U
434	        || alu_op == OP_CMPLT_U
435	        || alu_op == OP_CMPLE_U
436	        || alu_op == OP_CMPGT_F
437	        || alu_op == OP_CMPLT_F
438	        || alu_op == OP_CMPGE_F
439	        || alu_op == OP_CMPLE_F
440	        || alu_op == OP_CMPEQ_F
441	        || alu_op == OP_CMPNE_F);
442	    assign decoded_instr_nxt.compare = compare;
443	
444	    always_ff @(posedge clk)
445	    begin
446	        id_instruction <= decoded_instr_nxt;
447	        id_thread_idx <= ifd_thread_idx;
448	    end
449	
450	    always_ff @(posedge clk, posedge reset)
451	    begin
452	        if (reset)
453	            id_instruction_valid <= '0;
454	        else
455	        begin
456	            // Piggyback ifetch faults and TLB misses inside instructions, marking
457	            // the instruction valid if these conditions occur
458	            id_instruction_valid <= (ifd_instruction_valid || has_trap)
459	                && (!wb_rollback_en || wb_rollback_thread_idx != ifd_thread_idx);
460	        end
461	    end
462	endmodule
463

